#include <stdio.h>
#include <unistd.h>
#include <errno.h>
#include <limits.h>

int main() {
 char cwd[PATH_MAX];

 // Get and display initial working directory
 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("Initial CWD: %s\n", cwd);
 } else {
 perror("getcwd() error");
 return 1;
 }

 // Try to change directory
 if (chdir("/tmp") == 0) {
 printf("Successfully changed to /tmp\n");

 // Verify the change
 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("New CWD: %s\n", cwd);
 }
 } else {
 // Handle different error cases
 switch(errno) {
 case ENOENT:
 perror("Directory doesn't exist");
 break;
 case EACCES:
 perror("Permission denied");
 break;
 case ENOTDIR:
 perror("Path component is not a directory");
 break;
 default:
 perror("chdir() error");
 }
 return 1;
 }

 return 0;
}

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>

int main() {
 int dir_fd;

 // Open a directory using open() system call
 dir_fd = open("/home", O_RDONLY | O_DIRECTORY);
 if (dir_fd == -1) {
 perror("Failed to open directory");
 return 1;
 }

 printf("Directory opened with fd: %d\n", dir_fd);

 // Change to that directory using file descriptor
 if (fchdir(dir_fd) == 0) {
 printf("Successfully changed to /home using fchdir\n");

 char cwd[256];
 if (getcwd(cwd, sizeof(cwd)) != NULL) {
 printf("Current directory: %s\n", cwd);
 }
 } else {
 perror("fchdir failed");
 }

 // Close the directory file descriptor
 close(dir_fd);
 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <stdlib.h>

void daemonize() {
 pid_t pid;

 // Fork to create background process
 pid = fork();
 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 // Parent exits
 exit(EXIT_SUCCESS);
 }

 // Child becomes session leader
 if (setsid() < 0) {
 perror("setsid failed");
 exit(EXIT_FAILURE);
 }

 // Second fork to prevent acquiring a controlling terminal
 pid = fork();
 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 exit(EXIT_SUCCESS);
 }

 // CRITICAL: Change to root directory
 // This prevents blocking filesystem unmount
 if (chdir("/") == -1) {
 perror("chdir to / failed");
 }

 // Close standard file descriptors
 close(STDIN_FILENO);
 close(STDOUT_FILENO);
 close(STDERR_FILENO);

 // Redirect to /dev/null
 open("/dev/null", O_RDONLY); // stdin
 open("/dev/null", O_WRONLY); // stdout
 open("/dev/null", O_WRONLY); // stderr

 printf("Daemon running with PID: %d\n", getpid());
}

int main() {
 daemonize();
 // Daemon continues running in background
 while(1) {
 sleep(60);
 }
 return 0;
}
